import React, { useState, useEffect, useRef } from 'react';
import { datasetAPI } from '../services/api';
import { Button, Textarea, Alert, PageHeader, Card, Badge, EmptyState } from '../components/ui';
import ResultsPanel from '../components/ui/ResultsPanel';
import { FolderOpen, Upload, FileText, Trash2, Send, Sparkles } from 'lucide-react';
import './ConnectionsPage.css';
import './QueryPage.css';

const SAMPLE = [
  'Show total sales by category',
  'Which rows have missing values?',
  'Show top 10 records by revenue',
  'What is the average value per group?',
];

// Derive a safe table name from filename: "My Sales Data.csv" → "my_sales_data"
function toTableName(filename) {
  return filename.replace(/\.[^.]+$/, '').replace(/[^a-zA-Z0-9]+/g, '_').toLowerCase().slice(0, 60) || 'dataset';
}

export default function DatasetsPage() {
  const [datasets, setDatasets]   = useState([]);
  const [selected, setSelected]   = useState(null);
  const [question, setQuestion]   = useState('');
  const [result, setResult]       = useState(null);
  const [loading, setLoading]     = useState(false);
  const [uploading, setUploading] = useState(false);
  const [error, setError]         = useState('');
  const [success, setSuccess]     = useState('');
  const fileRef = useRef();

  // backend returns { schema, datasets: [{table_name, size, col_count, row_count}] }
  const load = () =>
    datasetAPI.list()
      .then(r => setDatasets(r.data?.datasets || []))
      .catch(() => setDatasets([]));

  useEffect(() => { load(); }, []);

  const upload = async e => {
    const file = e.target.files?.[0];
    if (!file) return;
    const tableName = toTableName(file.name);
    const form = new FormData();
    form.append('file', file);
    form.append('table_name', tableName);   // ← required by backend
    setUploading(true); setError('');
    try {
      await datasetAPI.upload(form);
      setSuccess(`"${file.name}" uploaded as table "${tableName}"!`);
      load();
    } catch (err) {
      const detail = err.response?.data?.detail;
      setError(typeof detail === 'string' ? detail : 'Upload failed.');
    } finally { setUploading(false); if (fileRef.current) fileRef.current.value = ''; }
  };

  const del = async (tableName, e) => {
    e.stopPropagation();
    if (!window.confirm(`Delete table "${tableName}"?`)) return;
    try {
      await datasetAPI.delete(tableName);   // DELETE /my-datasets/{table_name}
      load();
      if (selected?.table_name === tableName) setSelected(null);
    } catch { setError('Delete failed.'); }
  };

  const runQuery = async () => {
    if (!question.trim()) return setError('Please enter a question.');
    if (!selected)        return setError('Please select a dataset.');
    setLoading(true); setError(''); setResult(null);
    try {
      // nl-query-auto expects: { all_table_names: [...], question, limit }
      const { data } = await datasetAPI.query({
        all_table_names: datasets.map(d => d.table_name),
        question: question.trim(),
        limit: 100,
      });
      setResult(data);
    } catch (err) {
      const detail = err.response?.data?.detail;
      if (Array.isArray(detail)) setError(detail.map(d => d.msg || String(d)).join(', '));
      else setError(typeof detail === 'string' ? detail : 'Query failed.');
    } finally { setLoading(false); }
  };

  return (
    <div className="datasets-page fade-in">
      <PageHeader
        title="My Datasets"
        subtitle="Upload CSV or Excel files and query them with AI"
        actions={
          <>
            <input type="file" ref={fileRef} className="upload-input" accept=".csv,.xlsx,.xls" onChange={upload} />
            <Button icon={<Upload size={15}/>} loading={uploading} onClick={() => fileRef.current?.click()}>
              {uploading ? 'Uploading…' : 'Upload File'}
            </Button>
          </>
        }
      />

      {error   && <Alert type="error"   onClose={() => setError('')}   style={{marginBottom:16}}>{error}</Alert>}
      {success && <Alert type="success" onClose={() => setSuccess('')} style={{marginBottom:16}}>{success}</Alert>}

      <div className="datasets-layout">
        {/* ── Left ── */}
        <div className="datasets-input-col">
          <Card>
            <div style={{marginBottom:12,display:'flex',alignItems:'center',justifyContent:'space-between'}}>
              <span style={{fontSize:'0.78rem',fontWeight:700,color:'var(--gray-400)',textTransform:'uppercase',letterSpacing:'0.8px'}}>Your Datasets</span>
              <Badge color="gray">{datasets.length}</Badge>
            </div>

            {datasets.length === 0 ? (
              <div
                className="upload-zone"
                onClick={() => fileRef.current?.click()}
                onDragOver={e => e.preventDefault()}
                onDrop={e => {
                  e.preventDefault();
                  const f = e.dataTransfer.files[0];
                  if (f) upload({ target: { files: [f] } });
                }}
              >
                <div className="upload-icon"><Upload size={28}/></div>
                <div className="upload-title">Drop a file here</div>
                <div className="upload-sub">CSV or Excel (.xlsx) · Click to browse</div>
              </div>
            ) : (
              <div className="dataset-list">
                {datasets.map(d => (
                  <div
                    key={d.table_name}
                    className={`dataset-item ${selected?.table_name === d.table_name ? 'active' : ''}`}
                    onClick={() => setSelected(d)}
                  >
                    <FileText size={16} className="dataset-item-icon" />
                    <div className="dataset-item-info">
                      <div className="dataset-item-name">{d.table_name}</div>
                      <div className="dataset-item-meta">
                        {d.row_count ? `${Number(d.row_count).toLocaleString()} rows` : ''}
                        {d.col_count ? ` · ${d.col_count} cols` : ''}
                        {d.size ? ` · ${d.size}` : ''}
                      </div>
                    </div>
                    <button className="dataset-del-btn" onClick={e => del(d.table_name, e)}>
                      <Trash2 size={14}/>
                    </button>
                  </div>
                ))}
                <button
                  className="sample-btn"
                  style={{marginTop:4,textAlign:'center',color:'var(--accent)',fontWeight:600}}
                  onClick={() => fileRef.current?.click()}
                >+ Upload another file</button>
              </div>
            )}
          </Card>

          {selected && (
            <Card>
              <div style={{marginBottom:12,fontSize:'0.78rem',fontWeight:700,color:'var(--gray-400)',textTransform:'uppercase',letterSpacing:'0.8px'}}>
                Querying: <span style={{color:'var(--purple-600)'}}>{selected.table_name}</span>
              </div>
              <div className="query-form">
                <Textarea
                  label="Your Question"
                  value={question}
                  onChange={e => setQuestion(e.target.value)}
                  placeholder="e.g. Show total sales by category"
                  rows={3}
                  onKeyDown={e => { if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) runQuery(); }}
                  hint="Ctrl+Enter to run"
                />
                <Button onClick={runQuery} loading={loading} size="md"
                  icon={loading ? null : <Send size={14}/>} style={{width:'100%'}}>
                  {loading ? 'Running…' : 'Run Query'}
                </Button>
              </div>
            </Card>
          )}

          <div className="sample-questions">
            <div className="sample-title"><Sparkles size={13}/> Sample questions</div>
            {SAMPLE.map(q => (
              <button key={q} className="sample-btn" onClick={() => setQuestion(q)}>{q}</button>
            ))}
          </div>
        </div>

        {/* ── Right ── */}
        <div className="datasets-result-col">
          {loading && (
            <Card className="query-loading-card">
              <div className="query-loading">
                <div className="query-loading-spinner" />
                <div>
                  <div className="query-loading-title">Running AI pipeline…</div>
                  <div className="query-loading-sub">Schema → Gemini → SQL → Execute → EDA</div>
                </div>
              </div>
            </Card>
          )}
          {!loading && result && <ResultsPanel result={result} />}
          {!loading && !result && (
            <div className="query-empty">
              <div className="query-empty-icon"><FolderOpen size={32}/></div>
              <div className="query-empty-title">{selected ? 'Ask a question' : 'Select a dataset'}</div>
              <div className="query-empty-sub">
                {selected ? `Querying table: ${selected.table_name}` : 'Upload or select a CSV/Excel file on the left'}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
